code = """import json, re, pandas as pd

def load_records(obj):
    if isinstance(obj, str) and obj.endswith('.json'):
        with open(obj, 'r', encoding='utf-8') as f:
            return json.load(f)
    return obj

books = load_records(var_call_L5Bu8BzxzOSsNhFKec5lfxBu)
reviews = load_records(var_call_c4YlZw9x0gAohOKHDZJqAco5)

bdf = pd.DataFrame(books)
rdf = pd.DataFrame(reviews)

pattern = re.compile(r'\b(18\d{2}|19\d{2}|20\d{2})\b')

def extract_year_any(s):
    if not isinstance(s, str):
        return None
    m = pattern.search(s)
    return int(m.group(1)) if m else None

bdf['year'] = bdf['details'].map(extract_year_any)

def extract_num_id(x):
    if not isinstance(x, str):
        return None
    m = re.search(r'_(\d+)$', x)
    return int(m.group(1)) if m else None

bdf['num_id'] = bdf['book_id'].map(extract_num_id)
rdf['num_id'] = rdf['purchase_id'].map(extract_num_id)
rdf['rating'] = pd.to_numeric(rdf['rating'], errors='coerce')

joined = rdf.merge(bdf[['num_id','year']], on='num_id', how='inner').dropna(subset=['year','rating'])
joined['decade_start'] = (joined['year'].astype(int)//10)*10

books_per_decade = joined.drop_duplicates(subset=['num_id','decade_start']).groupby('decade_start')['num_id'].nunique().sort_values(ascending=False)
reviews_per_decade = joined.groupby('decade_start')['rating'].size().sort_values(ascending=False)

out = {
  'total_books_with_year': int(bdf['year'].notna().sum()),
  'total_joined_reviews': int(len(joined)),
  'distinct_joined_books': int(joined['num_id'].nunique()),
  'books_per_decade_top': books_per_decade.head(20).to_dict(),
  'reviews_per_decade_top': reviews_per_decade.head(20).to_dict()
}

print('__RESULT__:')
print(json.dumps(out))"""

